(window.webpackJsonp=window.webpackJsonp||[]).push([[15,5],{720:function(e,n,r){"use strict";var t;!function(e){e[e.Brief=0]="Brief",e[e["E-Mail"]=1]="E-Mail",e[e.Facebook=2]="Facebook",e[e.Instagram=3]="Instagram",e[e.Google=4]="Google"}(t||(t={})),n.a=t},741:function(e,n,r){"use strict";r.r(n);var t=r(53),l=r(290),h=r(112),d=(r(33),r(36),r(89),r(8),r(5),r(2)),c=r(306),o=r(301),m=r(18),k=r(720),w=r(201),f=Object(d.c)({__name:"CGuestbook",props:{value:null},setup:function(e){return{__sfc:!0,props:e,marked:c.a,CSlideshow:o.default,EEvent:m.a,ESource:k.a,DateTime:w.a}}}),T=r(69),component=Object(T.a)(f,(function(){var e=this,n=e._self._c,r=e._self._setupProxy;return n(t.a,{attrs:{id:"CGuestbook","max-width":"40em"}},[n(t.c,{staticClass:"secondary accent--text text-subtitle-2 text-md-subtitle-1 text-lg-h6"},[r.props.value.date?n("div",{domProps:{textContent:e._s(r.DateTime.format(r.props.value.date))}}):e._e(),e._v(" "),n("div",{domProps:{textContent:e._s("".concat(r.props.value.name," via ").concat(r.ESource[r.props.value.source]))}}),e._v(" "),n("div",{domProps:{textContent:e._s("".concat([r.props.value.organization,r.props.value.location].filter((function(e){return e})).join(", ")," "))}}),e._v(" "),r.props.value.category!==r.EEvent.RTC?n("div",{domProps:{textContent:e._s("Event: ".concat(r.EEvent[r.props.value.category]))}}):e._e()]),e._v(" "),r.props.value.title?n(t.e,{staticClass:"primary accent--text text-subtitle-1 text-md-h6 text-lg-h5"},[e._v("\n        "+e._s(r.props.value.title)+"\n    ")]):e._e(),e._v(" "),n(l.a),e._v(" "),r.props.value.text||r.props.value.imageUrls.length?n(t.d,[r.props.value.text?n("div",{staticClass:"text-body-2 text-sm-body-2 text-md-body-1 text-lg-h6 text-xl-h5",domProps:{innerHTML:e._s(r.marked.parseInline(r.props.value.text))}}):e._e(),e._v(" "),r.props.value.imageUrls.length?n(r.CSlideshow,{attrs:{value:r.props.value.imageUrls}}):e._e()],1):e._e(),e._v(" "),n(h.a,[r.props.value.answer?n("div",[n(l.a),e._v(" "),n(t.d,{staticClass:"text-body-2 text-sm-body-2 text-md-body-1 text-lg-h6 text-xl-h5"},[n("div",{domProps:{innerHTML:e._s(r.marked.parseInline("**RTC Köln:** *".concat(r.props.value.answer,"*")))}})])],1):e._e()])],1)}),[],!1,null,"722f4f5c",null);n.default=component.exports},764:function(e,n,r){"use strict";r.r(n);var t=r(73),l=r(53),h=r(47),d=r(39),c=r(2),o=r(74),m=r(741),k=(r(33),r(154)),w=(r(36),r(18)),f=r(720),T=r(40),F=r(41),S=Object(F.a)((function e(){Object(T.a)(this,e),this.answer="",this.category=w.a.RTC,this.imageUrls=[],this.location="",this.name="",this.organization="",this.source=f.a["E-Mail"],this.text="",this.title=""})),R=function(){function e(){Object(T.a)(this,e),this.value=new S}return Object(F.a)(e,[{key:"answer",value:function(e){return this.value.answer=e,this}},{key:"category",value:function(e){return this.value.category=e,this}},{key:"date",value:function(e,n){var r=arguments.length>2&&void 0!==arguments[2]?arguments[2]:1,t=arguments.length>3&&void 0!==arguments[3]?arguments[3]:0,l=arguments.length>4&&void 0!==arguments[4]?arguments[4]:0;return this.value.date=new Date(e,n-1,r,t,l),this}},{key:"imageUrl",value:function(e){return this.value.imageUrls.push(e),this}},{key:"location",value:function(e){return this.value.location=e,this}},{key:"name",value:function(e){return this.value.name=e,this}},{key:"organization",value:function(e){return this.value.organization=e,this}},{key:"source",value:function(e){return this.value.source=e,this}},{key:"text",value:function(e){return this.value.text=e,this}},{key:"title",value:function(e){return this.value.title=e,this}},{key:"build",value:function(){return this.value}}]),e}(),v=[(new R).date(2012,6).name("Wolfgang Alberg").organization("www.cardiofitness.de").source(f.a["E-Mail"]).text("\nHallo Sportfreunde,\n\\\n\\\nleider finde ich auf euer Homepage kein Gästebuch, möchte mich, auch im Namen weiterer 8 Mitfahrer unserer Gruppe bei euch für die Tour ab Zündorf bedanken.\n\\\n\\\nNeben der tollen Strecke und des netten Teams, habt ihr es auch geschafft die Sonne, entgegen aller Vorhersagen zu buchen.\n\\\n\\\nWir freuen uns schon auf die Tour im kommenden Jahr.\n\\\n\\\nMit sportlichen Grüßen\n\\\n\\\nWolfgang Alberg\n\\\nwww.cardiofitness.de\n").title("Ein großes Dankeschöööööön").build(),(new R).category(w.a.RTF).date(2012,6).name("Ursula Koepp").organization("TSV Weiss-Köln").source(f.a["E-Mail"]).text('\nLiebe Radsportfreunde,\n\\\n\\\nganz herzlichen Dank für die schöne RTF am Sonntag!\n\\\n\\\nWas Ihr da auf die Beine gestellt habt war super!\n\\\n\\\nEine landschaftlich tolle Strecke, Verpflegung vom Feinsten auf der 125er Strecke,\nimmer gut gelaunte Helfer u. selbst die angekündigten Gewitter hatten ein Einsehen mit Eurer Veranstaltung!\n\\\nAuch wenn auf den ersten Kilometern nachgeschildert werden musste (Spiel"kinder" gibt\'s immer), habt Ihr versucht uns eine perfekte RTF zu bieten!\n\\\nUnd Dank dem Track, den ich mir sicherheitshalber von Euer Homepage runter geladen hatte, ging auch orientierungsmäßig alles glatt.\n\\\n\\\nHerzliche Grüße aus Rondorf,\n\\\nUrsula Koepp\n').title("... ganz herzlichen Dank für die schöne RTF am Sonntag!").build(),(new R).category(w.a.RTF).date(2012,6).name("Günter").source(f.a["E-Mail"]).text('\nHallo Diana,\n\\\n\\\nhatte Norbert am Sonntag noch getroffen und ihm gesagt, dass es mir sehr gut gefallen hatte.\n\\\nObwohl ich ja etwas unmotiviert war und es vor der ersten Kontrolle noch ein kleines Scharmützel mit "Kollegen" gab,\nwurde es ein wirklich schöner Tag, der nicht so schnell zu topen ist!!!\n\\\n\\\nAlso nochmals: 10 Punkte und die Krone für eure schöne RTF!!!\n\\\n\\\nIhr habt das sehr liebevoll gestaltet.\n\\\nDie Kontrollen konnten sich absolut sehen lassen.\n\\\nAlle sehr freundlich und kein Zeitstreß.\n\\\nLiebe Leute kennengelernt.\n\\\nDas Wetter hatte bis zum Schluss gehalten.\n\\\nDas hebt die Laune ungemein.... :-)\n\\\nAlso euch allen vielen Dank für eure Mühe.\n\\\nNatürlich auch an Klaus-Anton und Thilo, mit denen es viel Spaß gemacht hat zu fahren....\n\\\n\\\nViele Grüße\n\\\n\\\nGünter\n').title("10 Punkte und die Krone für eure schöne RTF!!!").build(),(new R).category(w.a.RTF).date(2012,6).name("Dieter Reich").organization("ISB-Team-Cologne").source(f.a["E-Mail"]).text("\nHallo Radsportler des RTC-Köln,\n\\\n\\\ndanke für die gut ausgearbeitete Tour am 20.05.12.\n\\\nStrecke und Verpflegung wie immer prima.\n\\\nAber nicht zu vergessen die freundlichen Kontakte.\n\\\nSchön, dass es noch Radsportler gibt, die ihre Freizeit für diesen schönen Event opfern !!\n\\\n\\\nEs freut sich auf die nächste Veranstaltung, das benachbarte ISB-Team-Cologne\n\\\n\\\nSportliche Grüße\n\\\nDieter Reich\n").title("Danke für die gut ausgearbeitete Tour am 20.05.12").build(),(new R).category(w.a.RTF).date(2012,6).location("Monheim").name("Elke und Dieter").source(f.a["E-Mail"]).text("\nHallo liebe RTCler,\n\\\n\\\nherzlichen Dank für eine tolle Forsbachtour 2012.\n\\\nDer Tip unserer Freundin Marlies, unbedingt teil zu nehmen, hat sich wahrlich als Volltreffer erwiesen.\n\\\nEine sensationelle Streckenführung, gepaart mit der ausgesprochen guten Verpflegung\nund ergänzt durch das schöne Frühsommerwetter waren die Zutaten für einen sehr schönen RTF-Sonntag.\n\\\n\\\nNochmal herzlichen Dank an alle RTCler.\n\\\n\\\nViele Grüße aus Monheim am Rhein\n\\\nElke und Dieter\n").title("... eine tolle Forsbachtour 2012").build(),(new R).category(w.a.RTF).date(2012,5).name("Josef Witt").source(f.a["E-Mail"]).text("\nGuten Morgen,\n\\\n\\\nich bin gestern die 151 Strecke gefahren und wie ich um ca. 15.30 Uhr im Ziel wieder war wollte ich und meine drei anderen Radkollegen ein Grillwürstchen essen,\naber leider waren keine mehr da nur noch für die Jungs und Mädels vom Marathon das war sehr schade.\n\\\nDa wir den ganzen Morgen nur Waffeln und Riegel gegessen hatten.\n\\\n\\\nFür nächstes Jahr muss ich entweder schneller fahren oder eine kleinere Runde fahren damit ich noch ein Würstchen bekomme\noder ich bringe mir ein Paar mit die dann gegrillt werden können.\n\\\n\\\nAn der ein oder anderen Kontrolle habe ich die Bananen vermiest schade.\n\\\n\\\nAber man kann es ja auch nicht jedem recht machen.\n\\\n\\\nSonst war es eine sehr gute Veranstaltung!\n\\\n\\\nMit freundlichen Grüßen\n\\\nJosef Witt\n").title("Verpflegungsengpässe, sonst war es eine sehr gute Veranstaltung!").build(),(new R).category(w.a.RTF).date(2012,5).location("Kierspe").name("Michaela Bäcker").source(f.a["E-Mail"]).text('\nDer Tag danach ...\n\\\n\\\nSo, ich hatte gestern das große Vergnügen an dem Forstbach-Marathon 2012 teilzunehmen.\n\\\nDen Tag zuvor hatte ich noch wenig lust 200 km und ein paar gequetschte zu fahren.\n\\\nDie Wetterprognose war auch nicht so dolle, leichtes Gewitter war angesagt.\n\\\nAußerdem bedeutet so ein Marathon immer sehr früh aufzustehen ( in diesem Falle 04:30 Uhr ) :-)\n\\\nUnd mein Radkollege hat abgesagt - also genug Gründe, sich den Sonntag anders zu verplanen.\n\\\nWenn da nicht der innere Schweinehund den Kampf angesagt hätte ...\n\\\nUnd mal ehrlich meine Laune wäre am Sonntag nicht berauschend gewesen denn ...\n\\\n\\\nes war eine super gelungene RTF !!!\n\\\n\\\nLeider gab es anfangs Schwierigkeiten da irgend so ein Depp die Schilder die auf die Strecke führen sollten abmontiert hat ...\n\\\ndas ist ein übler Scherz wenn man denn 200 KM radeln möchte.\n\\\nDa kommt eine Wegsuche nicht gut.\n\\\nIch hatte das Glück einen Garmin dabei zu haben.\n\\\nIch hatte mir die Strecke Tags zuvor aufgeladen und konnte so die Streckenführung erkennen.\n\\\nDas wiederum hatte aber zu Folge, dass ich, anstatt wie geplant ganz locker anfangen, eine "Meute" hinter mir hatte die die Strecke nicht kannte\nund auch so ein Gerät nicht besaßen.\n\\\nDa fühlte man sich dann schon ein wenig "auf der Jagd" wenn die jungen Burschen hinter einem fröhlich Quatschen\nund spaß haben und man selber bei 85% der Maximalen HF die Strecke abfährt ;-)\n\\\nZum Glück war der Spuk nach 10 km erledigt und die Wegbezeichnung waren wieder sichtbar angebracht.\n\\\nSo konnte ich es dann ganz entspannt angehen lassen ...\n\\\nSchnell fand ich wieder in meinen Trott - und mit mir auch ein Radkollege dessen Name ich leider vergessen habe ( ? ).\n\\\nEr ist echt gut drauf.\n\\\nDer zog auf der Geraden ein Tempo, das war schon echt klasse.\n\\\nIch genoss es bei Ihm im Windschatten fahren zu dürfen.\n\\\nSo konnte ich auch die traumhafte Gegend genießen !!!\n\\\nBei KM 60/65 passierte mir dann leider eine Panne :-) Mein Vorderreifen hatte einen platten in der Abfahrt ...\n\\\nda habe ich Glück gehabt, das es mich nicht zerbröselt hat.\n\\\nZu diesem Zeitpunkt waren wir mit einem kleinen Pulk unterwegs.\n\\\nMein Kollege bekam von meinem Dilemma nichts mit.\n\\\nUnd so stand ich da mit einem Platten - Flickzeug hatte ich, aber leider keine Ahnung wie ich so einen Schlauch auch repariere bzw. austausche.\n\\\nUnd da gilt dann ganz klar der Spruch: "Ich bin so froh, das ich ein Mädchen bin"\n\\\nKeine 2 Minuten später kam ein Mitfahrer vom RTC Rodenkirchen und hat mir anstandslos geholfen.\n\\\nKurz darauf kam auch ein Wagen Vom RTC Köln und fragte ob er auch helfen könnte ...\n\\\nDas war unglaublich nett !!!!!\n\\\nSchön, das es solche Menschen gibt !!!!\n\\\nBei der nächsten Verpflegung wartete dann mein "Kollege" auch schon auf mich ;-)\n\\\nDie Verpflegungsstellen waren allesamt klasse !!!\n\\\nEs gab Kuchen, Rosinenstuten, Kekse, Weingummi, Riegel, und und und ...\n\\\nFür die Marathon\'is gab es sogar noch eine warme Mahlzeit.\n\\\nDas Wetter war auch absolut in Ordnung.\n\\\nEs kamen nur ein paar Tropfen runter und die konnte man genießen wurde es doch zum Ende der Tour mächtig warm mit Sonne !!!!\n\\\nFazit: Eine absolut lohnenswerte RTF - sehr nette, und hilfsbereite Helfer - super Gegend !!!!\n\\\nAuf diesem Wege auch noch mal ein herzliches Dankeschön für die nette Begleitung Namens ? - ohne ihn wäre ich nicht so schnell unterwegs gewesen.\n\\\n\\\nLieben Gruß\n\\\nMichaela Bäcker\n\\\nAus Kierspe\n').title("... eine super gelungene RTF !!!").build(),(new R).category(w.a.RTF).date(2012,5).location("Libur").name("Matthias Zimmer").source(f.a["E-Mail"]).text('\nSehr geehrte Damen und Herren,\n\\\n\\\nIch freue mich sehr wenn der Breitensport immer noch großen Zulauf findet.\n\\\nÜberhaupt keine Freude empfinde ich wenn Radsportbegeisterte ihre Freude widerrum schon Morgens um kurz nach 7 in reinen Wohngebieten lautstark zum Ausdruck bringen.\n\\\nSo geschehen heute Morgen in Libur (Freiheit/Stockumer Weg) Seit diesem Zeitpunkt war ich leider wach und konnte den Hochgenüssen der lautstarken Artikulation bestens folgen.\n\\\nEin weiterer Kritikpunkt ist: in den an Libur angrenzenden Feldern genießen viele ihre Freizeit, Hundehalter, Jogger, Walker\nund andere sind massivst durch unangemessene Geschwindigkeit Ihrer Fahrer gestört.\n\\\nAuch in Libur selber, sie kennen die Strassen wahrscheinlich, sind Ihre Teilnehmer unangemessen schnell unterwegs.\n\\\nIch selber durfte eine Gruppe "vorbeifliegender" Radler genießen.\n\\\n\\\nIch fasse meine Kritik noch einmal zusammen.\n- unangemessene Geschwindigkeit\n- zu hohe Lautstärke der Teilnehmer in reinen Wohngebieten zu nachtschlafender Zeit\n- bedingte Bereitsschaft zu gegenseitiger Rücksichtnahme\n- keine Signalisierung durch von hinten heraneilenden Radgruppen (Ihre Sportgeräte haben keine hohen Laufgeräusche)\n- keine Information der Anwohner, damit diese sich darauf einstellen können.\n\n\\\nIch gebe zu ich habe wahrscheinlich nicht die besten Exemplare erwischt, aber diese sind natürlich dann das Markenzeichen Ihrer Veranstaltung.\n\\\n\\\nmit freundlichen Grüssen\n\\\nMatthias Zimmer\n').title("Lärmbelästigung und Raserei").build(),(new R).category(w.a.RTF).date(2012,5).name("Monika und Helmut Moosmann").organization("RSG Ford").source(f.a["E-Mail"]).text("\nLiebe RTCler,\n\\\n\\\nCHAPEAU!!!\n\\\nWir sind zwar nur die 75-er (eigentlich waren es 84 km) gefahren, aber es war ein Traum!\n\\\nUnd besonders möchten wir die Verpflegung - hier besonders an der 1. Kontrolle - hervorheben.\n\\\nEin Genuss par excellence!\n\\\nDas Beste, was wir in unserer 8-jährigen RTF-Erfahrung erleben durften!\n\\\nAls Feinschmeckerin kann ich dies sehr wohl beurteilen: die tollen Kuchen, die liebevoll zubereiteten Brötchen mit Frischkäse und Garnitur und natürlich das Schmalzbrot.\n\\\nUnd keine WAFFELN!\n\\\nToll!\n\\\nIhr könnt auf eure Frauen stolz sein, super!\n\\\nUnd später am Ziel dann die wunderbare Quiche mit den zahlreichen Salaten habe ich genossen!\n\\\nVielen Dank nochmals für diese wunderbare Tour!\n\\\nHier spürt man euer Herzblut in aller Gänze!\n\\\nMacht weiter so.\n\\\n\\\nHerzlichst grüßen die RSGler (Ford)\n\\\n\\\nMonika u. Helmut Moosmann\n").title("CHAPEAU !!!").build()],z=[(new R).date(2014,6,19,18,43).name("Helga Hasberg").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...ich heute nach langer Zeit mal bei euch im Internet zu Gast war.\n\\\nErinnerungen wurden wach.\\Ich wünsche euch weiterhin für die Zukunft viel Erfolg und bei allen Touren gutes Gelingen.\n\\\n\\\nViele liebe Grüße\n\\\n\\\nHelga\n").build(),(new R).category(w.a.RTF).date(2014,5,28,12,36).name("Jessica Bosen").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...\n\\\n\\\n\\\nWas für ein Andrang schon um 6 Uhr?!\n\\\nIch gehörte nicht zu den Marathonfahrern, wollte eine der kleineren Strecken abfahren und stand plötzlich schon in einer anderen Warteschlange.\n\\\nEs kamen immer mehr und mehr Radfahrer, die genau so wie ich bei dem schönen Wetter früh starten wollten.\n\\\nAlle Kassenbetreuer gaben ihr Bestes, um die Anmeldungen so schnell wie möglich aufzunehmen.\n\\\nBei so einem Ansturm musste schon in den frühen Morgenstunden improvisiert werden.\n\\\n\\\nSo ein großes Kuchenbuffet mit hausgemachten Kuchen kannte ich bis dahin noch nicht.\n\\\nDie Kontrollen waren mit einer anderen sehr auffallenden Auswahl versehen: Brot, Marmelade, Weckchen, Hörnchen und Kekse.\n\\\nEndlich mal nicht die üblichen Waffeln, Bananen, oder sogar nur Waffeln, oder nur Bananen.\n\\\n\\\n\\\n\\\nBei der Streckenführung haben sich die Verantwortlichen sehr viel Mühe gegeben.\n\\\nDie zweitlängste Strecke war für mich mit 1653 hm ziemlich anstrengend,\naber der tolle Ausblick, die gut positionierten Kontrollstellen, das schöne Wetter und die abgelegenen Wege waren das Ganze mehr als Wert.\n\\\n\\\nDer Ansturm an Teilnehmern riss auch am späten Nachmittag nicht ab.\n\\\nDer Grill war durch seine große Auswahl an selbstgemachten Salaten und Grillwürstchen ununterbrochen stark besucht.\n\\\n\\\nNach Sonntag kann ich nun selbst mitreden und für mich war es ein tolles Erlebnis, endlich diese bekannte RTF kennengelernt zu haben.\n\\\nDas frühe Aufstehen an einem Sonntag hatte sich definitiv gelohnt.\n\\\n\\\nInsgesamt hieß es für den Veranstalter bei so vielen Besuchern den Überblick zu bewahren, was ihm und den fleißigen Helfern auch gut gelungen war.\n\\\nEin großes Kompliment an das Team, das trotz des großen Ansturms, sehr gut in dieser Situation reagiert hat.\n\\\n\\\nBis zum nächsten Jahr\n\\\nJessica\n").build(),(new R).category(w.a.RTF).date(2014,5,27,13,10).name("velotoerist").source(f.a["E-Mail"]).text('\nHallo RTC,\n\\\n\\\ndas war ein sehr schöner Radmarathon am Sonntag.\n\\\n\\\nEine tolle Strecke, weitgehend verkehrsarm und überwiegend recht gute Oberflächen (in der gewählten Richtung keine Selbstverständlichkeit),\nnettes Personal, sehr gute Ausschilderung und eine prima Verpflegung.\n\\\nAllein der Nudeltopf in Bebbingen war sensationell gut,\nauch wenn ich eigentlich kein Fan der warmen Verpflegung unterwegs bin, die liegt so schwer im Magen an den Folgenhügeln...\n\\\n(daher lieber nicht sooo lecker kochen oder - noch besser - im Ziel servieren)\n\\\n\\\nAuch davor und danach waren die Tische (bei uns) reich gedeckt.\n\\\nVielleicht sollte mancher "Schlemmermeier" einfach etwas früher losfahren, dann gibt\'s auch noch mehr.\n\\\nDa sind wir auch schon bei meinem einzigen Kritikpunkt:\n\\\nWenn eine Startzeit angegeben wird, würde ich es gut finden,\nwenn diese auch konsequent eingehalten würde und nicht bereits eine Viertelstunde (oder mehr) eher losgefahren wird.\n\\\nSollte doch kein Problem sein.\n\\\n\\\nAnsonsten: Weiter so! :-)\n\\\n\\\nBeste Grüße\n\\\nvelotoerist\n').title("RM").build(),(new R).category(w.a.RTF).date(2014,5,27,12,59).name("Helmut Hane").organization("www.sportlich-radeln.de").source(f.a["E-Mail"]).text("\nPrima RTF am vergangenen Sonntag.\n\\\nBericht über meine Fahrt auf der 150er Strecke jetzt auf meiner Website www.sportlich-radeln.de\n\\\n\\\nHelmut Hane\n").title("Prima RTF").build(),(new R).category(w.a.RTF).date(2014,5,27,9,28).name("Marco Gerlach").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich war am Sonntag auf der Marathon-Strecke unterwegs.\n\\\nDie Strecke war wirklich sehr sehenswert und gut ausgeschildert (auch wenn ich mich einmal verfahren habe, was aber an eigener Blindheit gelegen hat).\n\\\n\\\nOrga und Verpflegung waren Tiptop, da kann man nicht meckern!\n\\\n\\\nDanke, hat wirklich Spaß gemacht!\n\\\n\\\nGruß\n\\\nMarco Gerlach\n").build(),(new R).category(w.a.RTF).date(2014,5,27,9,26).name("Jörg Homann").organization("www.scan.bike`").source(f.a["E-Mail"]).text("\nEin langer Tag, nicht nur für die Fahrer auf den langen Strecken der Forsbach-Tour 2014, nein, auch für die Helfer des veranstaltenden Vereins RTC Köln 1972 e.V.\n- aber auch ein schöner Tag!\n\\\n\\\nBereits um 5:10 Uhr, mit kurzer Verspätung, öffneten sich die Türen der Sporthalle in der Heerstraße in Zündorf und blitzartig verteilten sich die helfenden Hände,\num mit den letzten Vorkehrungen ihre Stationen für den Andrang der Sportler vorzubereiten - und die kamen dann (wie üblich) sogar schon lange vor Öffnung der Anmeldung\nund warteten mehr oder weniger geduldig auf Kaffee und Startkarten.\n\\\n\\\nNeben den fünf herkömmlichen Anmeldetischen war auch scan&bike mit am Start, um die Athleten schnell auf die Strecke zu schicken - und das ging auch wieder richtig zügig,\nnach dem Scannen des auf http://scan.bike vorab gedruckten oder aufs Smartphone gespeicherten QR Codes und dem Bezahlen des Startgelds trägt der Laptop den Fahrer\n(ob Marathon oder kürzer, ob mit oder ohne Wertungskarte und sogar Trimmfahrer)\n\\\nper Mausklick im Bruchteil einer Sekunde in die Teilnehmerliste ein und sofort kommt der nächste an die Reihe\n- zeitraubende Handarbeit übernimmt der Computer und der einmal erzeugte\nQR Code gilt die ganze Saison - mit dem Laserdrucker ausgedruckt kann man ihn bis auf eine Kantenlänge von 2,5 cm verkleinern und auf die Wertungskarte kleben\noder laminieren und dadurch für die vielen RTF-/CTF-Teilnahmen konservieren - denn eines kann der Code nicht vertragen und das ist wenn er verwischt und undeutlich wird.\n\\\nAuch für den Veranstalter wird es leichter, wenn nach und nach immer mehr Sportler mit QR Code zur Einschreibung kommen kann eh schon knappes Personal reduziert werden\nund auch die langen Schlangen bei der Anmeldung entfallen durch die um ein Vielfaches kürzere Zeit des Einzelnen am Schalter.\n\\\nScannen, Kassieren, Klicken - Scannen, Kassieren, Klicken - Scannen, Kassieren, Klicken,â€¦ so geht scan&bike!\n\\\n\\\nDie jährliche Forsbach-Tour ist immer ein weiteres Highlight im RTF Kalender, bei besonders gutem Wetter wird die viele professionelle Arbeit des Vereins\nund seiner Mitglieder auch mit hohen Teilnehmerzahlen belohnt - mit scan&bike sind wir auf dem richtigen Weg die morgendliche Wartezeit zu minimieren\nund mit zum guten Gelingen einer Veranstaltung beizutragen.\n\\\n\\\nJörg Homann\n\\\nhttp://scan.bike\n").title("erfolgreicher Einsatz von scan&bike").build(),(new R).category(w.a.RTF).date(2014,5,27,6,49).name("Norbert Priefert").source(f.a["E-Mail"]).text("\nJetzt muss man hier aber mal einen Punkt machen und in die Bresche springen.\n\\\nKritik ist durchaus erlaubt, aber man muss, wenn man das macht, auch alle Umstände mit einbeziehen.\n\\\nHier wird aber in dem Beitrag alles, aber auch alles schlecht geredet.\n\\\nDer RTC-Köln organisiert eine solche Veranstaltung nicht zum ersten Mal.\n\\\nAm Sonntag war für den ausrichtenden Verein eine Rekordbeteiligung zu verzeichnen,\nmit der man -bei all der Erfahrung- nicht gerechnet hat und in dem Ausmaß auch nicht rechnen konnte.\n\\\nFast 1.300 Teilnehmer und man ist wahrscheinlich von einem Spitzenwert von 900 - 1.000 ausgegangen.\n\\\nUnd an einem Sonntag können ausgegangene Nahrungsmittel nicht mal so eben nachgeordert werden.\n\\\n\\\nSich jetzt an allem aufzuhängen und die Umstände die dazu geführt haben nicht zu berücksichtigen, ist gegenüber dem Veranstalter nicht fair.\n\\\nUnd mal ehrlich Herr General-Kritiker, wofür seid ihr denn überhaupt zur RTF gekommen?\n\\\nDoch nicht etwa wegen eurer Radsportbegeisterung.\n\\\nNein, ich hätte euch gleich nach dem Start ein schickes Cafe empfehlen können oder alternativ ein gutes Restaurant.\n\\\nEchten Radsportlern geht es doch vielmehr um den Radsport und das damit verbundene Erleben schöner Strecken.\n\\\nUnd wenn dann mal wirklich an einer Kontrolle was fehlt, was nicht der Regelfall sein sollte aber nachvollziehbar passieren kann,\nja dann fährt man zur nächsten Tanke und zieht sich da was rein.\n\\\nWie macht man das denn auf den Trainingsrunden, die länger ausfallen als geplant?\n\\\nIch nehme an, ihr seid schon große, selbständige Jungs; ansonsten empfehle ich euch einen Verein für betreutes Rennradfahren zu gründen.\n\\\nAuch wenn am Ende alles ausging, aus nachvollziehbarem Grund, die Veranstaltung war und bleibt toll!\n\\\n\\\nmit sportlich fairen Grüßen\n\\\nNorbert\n").title("Feedback auf die Generalkritk  ....wir sind enttäuscht von eurer Veranstaltung und kommen nicht nochmal wieder .").build(),(new R).category(w.a.RTF).date(2014,5,26,20,16).location("Recklinghausen").name("Jörg Freitag").source(f.a["E-Mail"]).text("\nHallo lieber RTC,\n\\\n\\\nich möchte mich bedanken für eine so tolle Tour.\n\\\nEs war eine sehr sehenswerte Strecke, ausrechend Verpflegung und sehr nette Stationshelfer.\n\\\nMir hat sehr gut gefallen und ich werde auf jeden Fall wiederkommen.\n\\\nGruß aus Recklinghausen\n\\\nJörg\n").title("Marathon").build(),(new R).category(w.a.RTF).date(2014,5,26,16,57).name("Markus Reckter").organization("www.rtf-koblenz.de").source(f.a["E-Mail"]).text("\nSehr geehrtes Team,\n\\\ndie Streckenwahl des Marathon war sehr schön, über verkehrsarme Straßen und durch landschaftliche Highlights perfekt gewählt.\n\\\nAuch das Profil war sportlich anspruchsvoll und ließ keine Wünsche offen.\n\\\nLeider war bei den letzten 2 Kontrollstellen keine Verpflegung mehr vorhanden.\n\\\nBis zur Warmverpflegung war diese sehr gut, danach wahrscheinlich durch die Fahrer auf den kürzeren schon verbraucht.\n\\\nVielleicht sollte, wie bei den Radmarathon Deutschland Veranstaltungen, die Verpflegung für die Marathonfahrer seperat sein.\n\\\n\\\nliebe Grüße aus Koblenz\n\\\nM.Reckter\n\\\nRTF Koblenz\n").build(),(new R).category(w.a.RTF).date(2014,5,26,13,8).name("Claudia Braun").organization("Union Biesfeld Triathlon").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\ndas war eine RTF wie aus dem Bilderbuch.\n\\\nStrecke (150), Verpflegung, Helfer, Wetter, alles passte.\n\\\nVielen lieben Dank für die hervorragende Organisation.\n\\\nIm nächsten Jahr gerne wieder!\n\\\nDank an die Jungs vom RC Schmitter fürs Ziehen :-)\n\\\n\\\nSportliche Grüsse\n\\\nClaudia Braun\n\\\nUnion Biesfeld Triathlon\n").build(),(new R).category(w.a.RTF).date(2014,5,26,12,50).name("Angela Schmilewski").organization("Fachwart RTC Mehlem").source(f.a["E-Mail"]).text("\nLiebe Orga des RTC Köln,\n\\\n\\\nich startete recht früh, da ich mich für die 156 km entschieden hatte.\n\\\n\\\nLandschaftlich einfach nur herrlich und sehr verkehrsberuhigte Strecken bei wunderbarem Wetter – besser ging es nicht !\n\\\n\\\nIch fand reichhaltige Verpflegungsstellen vor – von der 1. bis zur 4. - sowie freundliche Orga und Helfer – sowohl auf der Strecke als auch im Start- und Zielbereich.\n\\\n\\\nEin herzliches Dankeschön an Orga und Helfer und Euch allen eine gute Regeneration – die habt Ihr Euch jetzt verdient….\n").title("Wunderbare Veranstaltung").build(),(new R).category(w.a.RTF).date(2014,5,26,12,43).name("Dirk Brieden").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...\n\\\n\\\n\\\n\\\nWarum wurde meine Meinung von eben zu eurer Tour von gestern nicht abgedruckt?\n\\\n\\\nHabt ihr Angst vor Kritik?\n\\\n\\\nDirk\n\\\n\\\nPS: Hätte schon gedruckt werden müssen, da in der Zwischenzeit schon 2 neue Meinungen „reingestellt“ wurden.\n").build(),(new R).category(w.a.RTF).date(2014,5,26,10,55).name("Dirk Brieden").source(f.a["E-Mail"]).text('\nWir sind gestern euren Marathon gefahren.\n\\\n\\\nDie Strecke war wirklich schön,\n\\\n\\\n**ABER:**\n\\\neure Verpflegung war m. E. gesagt, das Allerletzte!\n\\\nEs gab keine Bananen (nur an 2 Kontrollen), keine Müsli-Riegel, keine Waffeln, keine Joghurts und die Getränke waren nicht isotonisch,\nda hätte man auch das Wasser aus der Sieg nehmen können.\n\\\nEure letzte Kontrolle war ein Totalausfall, da gab es gar nur Wurstscheiben, die den ganzen Tag schon von der Sonne "gebleicht" wurden.\n\\\nDabei braucht man nach 170km schon nochmal einen "Energieschub" durch Bananen, Müsli-Riegel, Waffeln oder ähnlichem.\n\\\nVon Ernährung für Radsportler habt ihr wirklich keine Ahnung.\n\\\n\\\n\\\nGetränke und Nahrung war das, was ihr insgesamt angeboten habt, eine Frechheit, da solltet ihr euch ein Beispiel an anderen Anbietern nehmen.\n\\\nDa tröstet auch das mittelmäßige Gulasch-Nudel-Angebot an einer Kontrolle nicht darüber hinweg, wobei Gulasch eh schwer im Magen liegt und ungeeignet ist.\n\\\nEuer gesamtes Verpflegungs-Angebot an den Kontrollen war nach dem Strickmuster "schön billig" zusammen gestellt und dafür 12 Euro zu verlangen, war eine Frechheit.\n\\\n\\\n\\\nEuer Ambiente am Start-/Zielplatz solltet ihr auch mal überdenken, bei jeder anderen RTF sind auch Anbieter für "Rad-Klamotten".\n\\\n\\\nEs war schlichtweg keine Atmosphäre, nur "Baller-Baller-Musik".\n\\\n\\\n\\\nEure Mitarbeiter bei der An-/Abmeldung schienen mit allem etwas überfordert.\n\\\nEs dauerte eine Ewigkeit, um nach der Tour unsere Serien-Karten zurück zubekommen, dabei saßen sie doch alle nur dumm rum und hatten nichts zu tun.\n\\\nNachdem wir alle von eurem Team angesprochen hatten und alle Mitarbeiter suchten, wurden die Karten dann gefunden.\n\\\n\\\n\\\n<u>**Fazit:**</u>\n\\\nWir sind enttäuscht von eurer Veranstaltung und kommen nicht nochmal wieder ☹\n').build(),(new R).category(w.a.RTF).date(2014,5,26,10,49).name("Michaela Packebusch").organization("VfB Polch Abtl. Radsport").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ... vielen Dank für die tolle Organisation und Verpflegung auf dem Marathon\n(besonders erwähnenswert fand ich den klasse Reiskuchen von Silvana J.\n\\\nNochmals vielen Dank an den Fahrer des Besenwagens, in dem ich leider sitzen musste als mein Material defekt war.\n\\\nLG Michaela\n\\\nvom VfB Polch Abtl. Radsport.\n").build(),(new R).category(w.a.RTF).date(2014,5,26,10,33).name("Frank Stöcker").source(f.a["E-Mail"]).text('\nHallo RTC,\n\\\n\\\neigentlich eine schöne Tour gesten , gut ausgesucht und bestens ausgeschildert .\n\\\n\\\nABER: keine Parkpätze mehr in der Nähe , keine Startnummern mehr ( 9.45 Uhr ! )  und bei der ersten Kontolle kaum noch was zu essen .\n\\\nNur noch Brotscheiben und trockene Keksreste.\n\\\nKein Obst, Riegel  NICHTS MEHR.\n\\\n\\\nAuch die Kollegen an der ersten Kontrolle waren genervt und nicht mit der besten Laune da.......\n\\\n\\\nZitat aus Euerm Flyer " Sehr gute Verpflegung an allen Kontollstellen und am Ziel"\n\\\n\\\nBei der 2. Kontrolle wieder kein Obst oder Riegel - die Kekse waren besser und ein bischen Gebäck mit Sirup .\n\\\nGetränke nur Tee.\n\\\n\\\nIm Ziel - Ihr könnt es Euch denken auch ziemlich tote Hose.\n\\\n\\\nDas ist für 12,- Euro für 2 Personen ein bisschen dürftig und hätte zumindest im Ziel in Form von Würstchen, Kuchen oder Teilerstattung ausgeglichen werden können.\n\\\n\\\nFrank\n').title("Feedback wegen Forsbach Tour 24.05.14").build(),(new R).category(w.a.RTF).date(2014,5,26,8,54).name("Reiche").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...\n\\\n\\\n\\\nvielen Dank für die Orga und die Auswahl der schönen Strecke.\n").build(),(new R).category(w.a.RTF).date(2014,5,26,8,15).name("Max Christian Obst").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\nDie RTF gestern war mal wieder klasse was die Strecke und das Wetter anging.\n\\\nFür den schlechten Straßenbelag teilweise könnt ihr ja nix.\n\\\nAber eine RTF wo es keine Bananen an den Verpflegungsstellen gibt, das geht gaaaaar nicht :D:D\n\\\nnächstes Jahr will ich wieder meine Banane bekommen ;)\n").build(),(new R).category(w.a.RTF).date(2014,5,26,7,24).location("Berrenrath").name("Stefan Schneider").organization("RV Morgenstern").source(f.a["E-Mail"]).text("\nHallo Sportskollegen vom RTC Köln.\n\\\nIch möchte euch ein großes Lob zu eurer gestrigen Veranstaltung aussprechen.\n\\\nEs passte einfach alles, Wetter, Verpflegung, Strecke.\n\\\nSo macht es Spaß Marathon zu fahren.\n\\\n\\\n\\\nMit Sportlichem Gruß,\n\\\n\\\nStefan Schneider\n\\\n1.Vorsitzender RV Morgenstern Berrenrath\n").build(),(new R).category(w.a.RTF).date(2014,5,26,7,6).name("Norbert Priefert").organization("www.rtc-rodenkirchen.de").source(f.a["E-Mail"]).text("\nHallo RTC Köln´ner,\n\\\n\\\ndas war wirklich super Klasse!!\n\\\nTolle Organisation, freundliches und hilfsbereites Team, eine sehr schöne und interessante Streckenführung und -Gott sei Dank- das Wetter phantastisch.\n\\\nÜber 1200 Teilnehmer haben`s euch gedankt.\n\\\nKlasse!\n\\\nNach der Wasserschlacht von vergangenem Jahr habt ihr euch das auch wirklich verdient!\n\\\nEigentlich kann man das gar nicht toppen…eigentlich..\n\\\nDie Messlatte habt ihr wirklich hoch aufgehängt, aber, wir vom RTC-Rodenkirchen nehmen dies als Herausforderung an.\n\\\nWir werden unser Bestes geben um zumindest annähernd euer Niveau zu erreichen.\n\\\nVersprochen!\n\\\nAlso dann, bis Samstag, 14.06.2014 am Bildungswerk in Köln-Sürth, mit ebenfalls tollen Strecken, motiviertem Team und hoffentlich grandiosem Wetter.\n\\\n\\\nBis denne,\n\\\nNorbert\n").title("Feedback wegen RTF 2014 -..eigenlich kann man das gar nicht toppen...").build(),(new R).category(w.a.RTF).date(2014,5,25,19,44).name("Jürgen Ruttkowski").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...\n\\\n\\\ndie Forsbachtour am 25.05.2014, bei bestem Wetter, ein voller Erfolg war und die Strecke (115 km) hervorragend ausgesucht ist.\n\\\n\\\n\\\n\\\nViele Grüße und den besten Dank an alle die zum Gelingen beigetragen haben\n\\\n\\\nJürgen Ruttkowski\n").build(),(new R).date(2014,1,17,11,9).name("Roland Schultz").source(f.a["E-Mail"]).text('\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...\n\\\n\\\nam 29.5.14 wird ein interessanter Radwanderweg  eröffnet.\n\\\nAuf der ehemaligen Bahntrasse, genannt "Balkanexpress" Startpunkt Bahnhof Leverkusen-Opladen\nüber Burscheid, Wermelskirchen, Remscheid, Hückeswagen, Wipperfürth bis nach Marienheide.\n\\\nEmpfohlene Weiterfahrt über Lindlar nach Köln.\n\\\nAlternative zurück bis Wipperfürth nach Köln.\n\\\nWunderbar ausgebaut.\n\\\nKleine Einschränkungen in Wermelskirchen.\n\\\nHier sollte man genau auf die Ausschilderung achten.\n\\\nEin Teilstück ist bereits eröffnet. Einstieg auf der Landstraße Opladen, Richtung Burscheid.\n\\\nEinstieg bei Haus Sonnenschein.\n\\\nBin die Strecke mit großer Freude einigemale gefahren.\n\\\nWeitere Infos im Internet.\n\\\nUnser RTC-Trikot habe ich voriges Jahr auf 2000 m Höhe auf einen ehemaligen Vulkangebiet in Hawaii ausgefahren.\n\\\n\\\nmit einem "All Heil"\n\\\nRoland Schultz\n').title("Feedback wegen ... Roland Schultz").build()],M=[(new R).category(w.a.CTF).date(2015,10,19,12,55).name("Claude-Antoine Berger de Leon").source(f.a.Facebook).text("\nAuch von meiner Seite einen großen Dank an den Veranstalter, der einen enormen Aufwand betrieben hat.\n\\\n\\\nObwohl es die erste Veranstaltung dieser Art für den Verein war, wurde an Alles gedacht und es war eine sehr gelungene CTF,\nbei der die Teilnehmer einen Riesenspaß haben konnten.\n\\\nEs ist zu hoffen, dass im nächstem Jahr eine Wiederholung der Veranstaltung stattfinden kann\nund dass auch vielleicht noch einige andere Vereine aus der Region die für Viele noch etwas unbekannte Veranstaltung in Angriff nehmen ...\n").build(),(new R).category(w.a.CTF).date(2015,10,18,18,43).name("Helmut Kanthak").organization("RSC Nievenheim").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...eure Orga perfekt war und wir vom RSC Nievenheim beim nächsten mal wieder dabei sind.\n\\\nVerpflegung war superund auch das man das Rad kurz abspülen konnte war toll.\n\\\nDanke für eine so schöne Tour.\n\\\n8-)\n\\\nHelmut vom RSC Nievenheim\n").title("Feedback wegen ...CTF 1. Wahnbach - Tour").build(),(new R).category(w.a.CTF).date(2015,10,18,14,23).name("Schonneb Aus Lev").source(f.a.Facebook).text('<a href="https://www.youtube.com/v/Z2MqTVOeZMM" target="_blank">https://www.youtube.com/v/Z2MqTVOeZMM<a/>').title("... kleines Video von gestern").build(),(new R).category(w.a.CTF).date(2015,10,18,14,22).name("Jür Jen").source(f.a.Facebook).text("\n... die sich die Zeit genommen haben und die tolle Arbeit für uns Teilnehmer gemacht habt!!\n\\\nStrecke war prima, leckere Verpflegung (Wurstbrote 😉) auch der Wasserschlauch fürs Rädchen war gut!\n\\\n\\\nHoffentlich gibt es nächstes Jahr die 2. Wahnbach-Tour, ich bin wieder dabei .....\n").title("Besten Dank an ALLE Helfer ...").build(),(new R).category(w.a.CTF).date(2015,10,18,13,49).name("Manuela 'Ela' Huber").source(f.a.Facebook).text("\ntotal nette Crew - super Strecke - hat viel Spaß gemacht!!\n\\\ngerne wieder!!\n").build(),(new R).category(w.a.CTF).date(2015,10,18,10,33).name("Jo Di").source(f.a.Facebook).text("\nIhr seid ein richtig nettes Team und ein toller Verein, da konnte das Wetter doch nur mitmachen.\n\\\nStrecke war toll und an den Kontrollstellen gab's immer lekker Verpflegung (Klasse die wärmende Brühe und Liebe-Wurst-Käse belegten Brote) und immer ein nettes Gespräch.\n\\\nHat uns viel Spaß gemacht.\n\\\nDanke\n\\\n\\\nPs. Dank suuuuper Waschmöglichkeit vor Ort konnten wir uns zuhause gleich aufs Sofa hauen.\n\\\n\\\nPs.Ps. Schmalzbrotgrüsse\n").build(),(new R).category(w.a.CTF).date(2015,10,18,8,22).name("Guido Faßbender").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nEure 1. CTF war eine klasse Veranstaltung.\n\\\nVielen Dank für die Mühe, die Ihr Euch damit gemacht habt.\n\\\nDie Streckenführung war sehr gut gewählt.\n\\\nEuro Verpflegung war -wie offenbar bei Euch üblich- sehr gut.\n\\\nAn der entferntesten Kontrolle wären vielleicht ein paar Schmalzbrote ganz okay gewesen ;-)\n\\\n\\\nIch fand Eure Ausschilderung sehr gut gemacht.\n\\\nIn Kombination mit den aktualisierten Tracks konnte da eigentlich nichts mehr schief gehen.\n\\\nObwohl das Zusammenspiel mit Fußgängern/Joggern mehr als in Ordnung war, könnte ich mir vorstellen, dass die eine oder andere Markierung verschwunden ist.\n\\\n\\\nAlles in allem eine tolle Veranstaltung.\n\\\nBin nächstes Jahr wieder dabei.\n\\\n\\\nGuido Faßbender\n").build(),(new R).category(w.a.CTF).date(2015,10,17,21,2).name("Schonneb Aus Lev").source(f.a.Facebook).text("\nHallo Zusammen,\n\\\nvielen Dank an das OrgTeam und die fleissigen Helfer.\n\\\nMir hat die Strecke sehr gut gefallen, Verpflegung super, Rad war zum Schluß auch noch sauber (meine Frau fragte, ob ich überhaupt gefahren bin) - also rundum gelungen.\n\\\n\\\nIch würde mich auf ein nächstes Mal sehr freuen.\n").build(),(new R).category(w.a.CTF).date(2015,10,17,20,45).name("Henning Rudolph").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nvielen Dank für die Organisation der CTF.\n\\\nDie Verpflegung an euren Kontrollstellen und die freundlichen Helfer überall waren top!\n\\\nVor allem der warme Tee und die heiße Brühe waren heute klasse.\n\\\nAuch im Zielbereich hat es an nichts gefehlt.\n\\\nEinzig die Ausschilderung bis zur ersten Kontrolle war teilweise nicht vorhanden oder sehr schwer zu sehen.\n\\\nDanach hat es gepasst.\n\\\nDank GPS-Gerät und Track von Euch ging es aber.\n\\\n\\\nMacht weiter so!\n\\\nFür nächstes Jahr wünsche ich Euch etwas Sonnenschein, damit noch mehr Biker kommen.\n\\\n\\\nSportliche Grüße,\n\\\nHenning\n").build(),(new R).category(w.a.CTF).date(2015,10,17,20,1).imageUrl("https://content.rtc-koeln.de/pages/guestbook/2015-10-17_20-01.jpg").name("Wilfried Goesgens").source(f.a.Facebook).text("\nAuch wenn ich das Startfenster leicht gerissen habe und nur die kurze Tour nehmen konnte 😕\n\\\nSuperrunde und hoffentlich nächstes Jahr wieder ...\n").build(),(new R).category(w.a.CTF).date(2015,10,17,19,38).imageUrl("https://content.rtc-koeln.de/pages/guestbook/2015-10-17_19-38.jpg").name("Thorsten Klein").source(f.a.Facebook).text("\nTolle Strecke.\n\\\nHat Spaß gemacht.\n\\\nDanke für die Orga.\n\\\nEs sollte mehr CTF geben.\n\\\n\\\nDie Möglichkeit das Rad direkt vor Ort zu reinigen fand ich auch klasse.\n\\\n\\\nHier auch noch ein Bild von dem Ausblick auf der Strecke.\n").build(),(new R).category(w.a.CTF).date(2015,10,17,19,3).name("Sabine Riehl").source(f.a.Facebook).text("Superschöne Strecke, tolle Verpflegung: hat total Spaß gemacht - vielen Dank für diese CTF und allen, die Sie möglich gemacht haben ...").build(),(new R).category(w.a.CTF).date(2015,10,17,18,57).name("Jörg Hengster").source(f.a.Facebook).text("\nSuper Tour heute!\n\\\nSchöne Strecke, direkt in den Wald, leckere Verpflegung.\n\\\nGute Idee, hier mal eine CTF anzubieten.\n\\\nDanke RTC!\n").build(),(new R).category(w.a.CTF).date(2015,10,17,17,52).name("Bernd Doelp").source(f.a.Facebook).text("\nHallo RTC,\n\\\n\\\nvielen Dank für eure heutige Veranstaltung.\n\\\nIhr habt eine wunderschöne Strecke und perfekte Kontrollstellen auf die Beine gestellt.\n\\\nGerade in Zeiten schwindender Radveranstaltungen, geht Ihr den anderen Weg und organisiert eine Zweite.\n\\\nRESPEKT!!\n\\\nIch hoffe, dass Ihr es auch nächstes Jahr schafft dieses Event zu veranstalten.\n\\\nAlso bitte weiter so.\n\\\n\\\nUnd nun den einzigen Kritikpunkt, an der Ausschilderung müsst Ihr echt noch arbeiten.\n\\\nEin Kontrollfahrer am Morgen würde hier Wunder wirken.\n\\\nIch für meinen Teil freue mich jetzt schon auf's nächste Jahr.\n\\\n\\\nMit sportlichem Gruß\n\\\nBernd Doelp\n").title("Feedback vom CTF").build(),(new R).category(w.a.CTF).date(2015,10,17,16,45).name("Ben Feld").source(f.a.Facebook).text("\nDanke für die schöne Veranstaltung!\n\\\nDie Strecke war ausgesprochen schön und überall, wo nicht irgendwelche Deppen die Schilder umgedreht oder abgerissen haben, prima ausgezeichnet.\n\\\n\\\nWiederholung im nächsten Jahr ist ausdrücklich erwünscht.\n").build(),(new R).category(w.a.CTF).date(2015,10,17,16,7).name("Stephan Schwarz").source(f.a["E-Mail"]).text("\nHallo,\n\\\n\\\nder CTF heute hat mir sehr gut gefallen.\n\\\nTolle Strecke, sehr gute Verpflegung, sehr nette Personen an den Verpflegungspunkten.\n\\\n\\\nDanke aus Hennef\n\\\nStephan\n").title("Wahnbachtal Tour").build(),(new R).category(w.a.RTF).date(2015,6,3,20,16).name("Guido Faßbender").organization("Grenzfahrer e.V.").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nvielen Dank für die tolle Marathonstrecke, die sehr gute und ausreichende Verpflegung und überhaupt für die ganze Veranstaltung.\n\\\nBin nächstes Jahr sicher wieder dabei.\n\\\nNix ändern :-))\n\\\n\\\nSportliche Grüße\n\\\n\\\nGuido Faßbender\n\\\nGrenzfahrer e.V.\n").title("Feedback wegen Marathon").build(),(new R).category(w.a.RTF).date(2015,6,3,12,36).name("Frank Koch").source(f.a["E-Mail"]).text("\nReiskuchen,\n\\\nder Reiskuchen von Silvana war wieder mal der Knaller.\n\\\nKann mir evtl einer das Rezept verraten????\n\\\nFür eure Mühe und Antwort danke ich im voraus\n\\\nmfg Frank\n").title("Re: RTF").build(),(new R).category(w.a.RTF).date(2015,6,3,9,31).name("Frank Koch").source(f.a["E-Mail"]).text("\nguten Mogen,\n\\\nkann mich da meinen Vorrednern nur anschließen eine sehr schöne RTF war das.\n\\\nBin die 118er Runde gefahren die es ja auch schon mit ihren 1600 Hm in sich hatte.\n\\\nDa taten die Beine doch schon ein bisschen weh.\n\\\nDie Landschaft um Eitorf und Much ist sehr schön.\n\\\nAlle Leute im K Bereich waren sehr nett und zuvorkommend.\n\\\nAn dieser Stelle noch mals besten Dank an Harald für mein gefundenes Handy.\n\\\n\\\nschöne Grüße aus Troisdorf Frank 😊\n").title("RTF").build(),(new R).category(w.a.RTF).date(2015,6,2,10,45).name("Frank Oesterheld").source(f.a.Facebook).text('\nDie Versorgungen an allen "K" super und vor allem die Supporter hilfsbereit, nett und gut gelaunt ...\n\\\nDas ist nicht selbstverständlich und nicht auf allen Veranstaltungen so.\n\\\nDas spricht für ein tolles Klima im Team RTC Köln e. V. 1972 !!\n\\\nBis zum nächsten Jahr 😊\n').title("Kommentar zu Schnappschüssen / Impressionen von der K5 auf der Forsbach-Tour 2015").build(),(new R).category(w.a.RTF).date(2015,6,1,22,47).name("Gerhard Veeh").source(f.a.Facebook).text("\nWir, der RTC-Mehlem 1984 e. V., waren nur zu zweit am Start wg. der Terminkollision mit ByBike.\n\\\nNächstes Mal sind wir wieder mehr und beim Marathon dabei ...\n\\\n\\\nDanke Euch für die tolle Organisation.\n").build(),(new R).category(w.a.RTF).date(2015,6,1,20,33).name("Fam Rossol").organization("1. RTW-Sankt Augustin-Menden").source(f.a["E-Mail"]).text("\nNach der ersten Kontrolle haben wir uns aufgeteilt und in Gruppen die 70er, 100er und die 150er Strecke unter die Räder genommen.\n\\\nIm Ziel waren wir uns einig - es war wieder eine tolle Veranstaltung bei euch - DANKE an ALLE Helfer, Freunde und Sponsoren des RTC !!!!\n\\\n\\\nDie Radsportfreunde vom 1. RTW-Sankt Augustin-Menden\n").title("Danke ...").build(),(new R).category(w.a.RTF).date(2015,6,1,15,57).name("Christof Mourikis").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...\n\\\n\\\nSENSATIONELL!!!!!\n\\\n\\\nDie Strecke    150 von 100 möglichen  Punkte\n\\\nHöhenmeter   reichlich!\n\\\n\\\nAusschilderung  150 von 100 möglichen  Punkte\n\\\n\\\nVerpflegung 150 von 100 möglichen  Punkte\n\\\n\\\nWas will der Radsportler mehr??\n\\\n\\\nKetten-Checks, für den der es braucht!\n\\\n\\\nBeste Marathon-Veranstaltung, die ich bisher gefahren bin (und das sind nicht wenige!)\n").title("Feedback wegen 43. Marathon am 31.05.2015").build(),(new R).category(w.a.RTF).date(2015,6,1,14,14).name("Yvonne Basinski").source(f.a.Facebook).text("\nTotal schöne Tour.\n\\\nTop Verpflegung und Beschilderung.\n\\\nVielen Dank an das Orga Team!\n\\\nWir sind nächstes Jahr wieder dabei.\n").build(),(new R).category(w.a.RTF).date(2015,6,1,9,5).name("Marc Grewe").source(f.a["E-Mail"]).text('\nHallo RTC,\n\\\n\\\ndanke mal wieder für die tolle Tour!\n\\\nMan glaubt ja manchmal gar nicht, wie schön wir es im Bergischen haben.\n\\\nIch komme gerne wieder!!\n\\\nVielleicht gelingt es euch ja sogar den Termin von der BN-Eupen-BN Tour zu trennen, die will ich nämlich auch mal angehen.\n\\\nVerpflegung fand\' ich angemessen gut, auch wenn das Gulasch später an den Anstiegen noch mal Hallo sagen wollte ;-)\n\\\n\\\nWas mich allerdings schon wundert ist eure Angabe der Hm für die Marathonstrecke:\n\\\nalso mein Garmin hat knappe 2300 hm aufgezeichnet, mit topografischen Korrekturen könnte man vielleicht noch knappe 2400 hm rausschlagen.\n\\\nAber 2700 hm sind einfach nicht drin.\n\\\nNicht, dass ich mehr bräuchte, aber es ist schon unterwegs irritierend, weil man zum Gulasch (55% der Strecke) gerade mal 1100 hm (40% von 2700 hm) hat\nund denkt, was denn da wohl noch alles von einem liegen soll?\n\\\n\\\nLeider habe ich auch alle Abzweigungen zum "Kettencheck" verpasst (was mir zum Ende hin wohl auch ganz recht war ;-)).\n\\\nOb ihr das wohl bitte im kommenden Jahr deutlicher ausschildern könntet?\n\\\n\\\nWie stellt ihr die Streckenlänge eigentlich so genau fest?\n\\\nIch hatte jetzt zum zweiten Mal die 200km gerade erst auf dem Schulhof geknackt…\n\\\nAber gut, wir reden hier von einem Prozent Abweichung.\n\\\nIch fand euer 200km-Schild jedenfalls sehr schön J (auch wenn mir da noch gute 2km auf dem Tacho fehlten)\nund auch euer "1km bis zum Ziel" Schild steht was früh auf der Strecke,\naber es steigt ja keiner 400m vor dem Ziel ab und beruft sich auf das Schild ;-).\n\\\n\\\nNochmals danke und bis zum nächsten Mal!\n\\\n\\\nMarc\n').build(),(new R).category(w.a.RTF).date(2015,5,31,20,30).name("Petra Ak").source(f.a.Facebook).text("Vielen Dank für's Organisieren, war super !").build(),(new R).category(w.a.RTF).date(2015,5,31,20,19).name("Thomas Mühl").source(f.a.Facebook).text("\nFür den Regen am Schluss könnt ihr ja nichts, ansonsten Top Veranstaltung, da können sich andere Veranstalter mal 'ne Scheibe von abschneiden.\n").build(),(new R).category(w.a.RTF).date(2015,5,31,20,11).name("Michael Kalisch").source(f.a.Facebook).title("top top top 😊").build(),(new R).category(w.a.RTF).date(2015,5,31,20,10).name("Horst Voll").source(f.a.Facebook).text("War geil und sehr anstrengend ! 👍").build(),(new R).category(w.a.RTF).date(2015,5,31,19,29).imageUrl("https://content.rtc-koeln.de/pages/guestbook/2015-05-31_19-29.jpg").name("Horst Paesch").source(f.a.Facebook).text("\nDanke für ein perfekt organisierten Marathon, die Strecke war super ausgesucht, viele ruhige Straßen, tolle Ausblicke!\n\\\nDie Damen und Herren an den Kontrollpunkte/Verpflegungspunkten waren alle sehr nett und hilfsbereit, die Verpflegung ist der Knaller.\n\\\n\\\nDa nimmt man beim Marathon noch zu 😊\n").build()],V=[(new R).category(w.a.CTF).date(2016,10,31).name("Rolf Müller").organization("Cito Hennef-Geistingen").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nes war meine erste CTF und ich bin begeistert.\n\\\nNachdem wir früh auf die „Beschilderung“ mit den Bändern aufmerksam gemacht wurden, hatten wir keine Probleme mit der 35er Strecke,\nobwohl wir nur mit normalen Trekkingrädern unterwegs waren!\n\\\nMan konnte immer wieder merken, dass hier Leute am Werk waren, die etwas vom Fach verstehen!\n\\\n\\\nIch freue mich schon auf das nächste Jahr!\n\\\n\\\nRolf Müller, Cito Hennef-Geistingen\n").build(),(new R).answer("310 Teilnehmer waren's").category(w.a.CTF).date(2016,10,30,20,30).location("Hürth Berrenrath").name("Stefan Schneider").organization("RV Morgenstern").source(f.a.Facebook).text("\nDie CTF war gestern erste Sahne, nur bei den Flatterbändern hättet ihr das eine oder andere mehr aufhängen können.\n\\\nIch war ganz froh meinen Garmin dabei gehabt zu haben.\n\\\nWie viele Teilnehmer hattet ihr eigentlich?\n").build(),(new R).answer("Der Tacho wurde gefunden, der Finder hat sich bei uns gemeldet - danke nochmal dafür - und Jörg hat ihn heute (31.10.) auch schon zurück bekommen ...").category(w.a.CTF).date(2016,10,29,19,21).name("Jörg Moritz").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich wollte nur sagen, dass euch die CTF sehr gut gelungen ist.\n\\\nVor allem die zweite Beschilderung nach einer Abzweigung gibt einem Sicherheit, dass man richtig ist.\n\\\n\\\nMir ist im Startbereich leider ein Mißgeschick passiert.\n\\\nAuf den ersten ca. 200m habe ich meinen Radcomputer verloren.\n\\\nFalls also jemand einen Sigma ROX 6.0 CAD gefunden hat, wäre es schön, wenn der Kontakt hergestellt werden könnte.\n\\\n\\\nGrüße\n\\\nJörg Moritz\n").title("Feedback wegen CTF").build(),(new R).category(w.a.CTF).date(2016,10,29,20,30).name("Jürgen Rohr").source(f.a.Facebook).text("\nSchöne Runde bei gutem Wetter und sehr guter Verpflegung.\n\\\nHat Spaß gemacht.\n\\\nVielen Dank an das Orga-Team!!!\n").build(),(new R).category(w.a.CTF).date(2016,10,29,20,30).location("RSC Erftstadt").name("Horst Paesch").source(f.a.Facebook).text("\nWenn ich mal was konstruktives sagen darf, es war eine super spannende CTF, sehr abwechslungsreich,\ndie spärliche Beschilderung im Wald mit rotweißem Absperrband möchte ich garnicht kritisieren,\nich fand es sehr spannend und man kam dadurch mit den Kollegen ins Gespräch.\n\\\nAlso, wie gewohnt vom RTC, eine tolle Veranstaltung.\n").build(),(new R).category(w.a.CTF).date(2016,10,29,20,30).location("RTV Lohmar").name("Se Sandra").source(f.a.Facebook).text("\nIch fands geil!\n\\\nSollte mehr davon bei uns hier geben 😊\n").build(),(new R).category(w.a.CTF).date(2016,10,29,20,30).name("Bernd Doelp").source(f.a.Facebook).text("Vielen Dank für die schöne Tour und bis nächstes Jahr").build(),(new R).category(w.a.CTF).date(2016,10,29,20,30).name("Jörg Marso").source(f.a.Facebook).text("\nEs hat super viel Spaß gemacht und die Verpflegung war Spitze.\n\\\nDenke ich war der einzige mit einem Pedelec, habe sonst keins gesehen.\n\\\nWir sehen uns dann 2017.\n").build(),(new R).category(w.a.CTF).date(2016,10,29,20,30).name("Marcus Wilden").source(f.a.Facebook).text("Schöne Tour bei bestem Wetter").build(),(new R).category(w.a.RTF).date(2016,5,31,1,34).name("Gunter Maier").source(f.a.Facebook).text('\nMir kommt es auch so vor als ob ich zugenommen habe, trotz der drei Varianten die wir gefahren sind (welche sich mMn auch sehr gelohnt haben).\n\\\nIhr ward alle total lieb und ich verzeihe euch, uns keinen Espresso zum Croissant gereicht zu haben 😀\n\\\n\\\nAlles super und eine toll ausgearbeitete Strecke (bezogen auf den Marathon, die anderen bin ich ja nicht gefahren).\n\\\n\\\nIhr wollt Kritik, meine wäre diese:\n\\\nGanz am Anfang Kreuzung Hermann-Löss-Straße / Frankfurter Straße habt ihr zusätzlich zu den beiden Verkehrszeichen "Stopp" einen eigenen Warnhinweis angebracht,\ndamit durchdringt ihr ein einheitliches System und müsstet eigentlich jedes weitere Verkehrszeichen welches auf eine Gefahr hinweist bzw. ein Gebot vorgibt doppeln.\n\\\nMacht man aber nicht weil solche Sicherheitssysteme einfach und verständlich gehalten werden sollen.\n\\\nSo könnte es dazu führen dass am nächsten Stoppschild wo kein zusätzliches Schild hängt,\nman von keiner Relevanz für einen selbst ausgeht und man einfach drüber fährt ("vor allem wenn er schon im Tunnel fährt").\n\\\nIch glaube ein klarer Hinweis auf die StVO und deren Einhaltung reicht aus, da sie ein erprobtes System darstellt.\n\\\n\\\nAnders sieht es jetzt aus, wenn z.B. eine Abfahrt kommt und darin Schlaglöcher oder sonstige Gefahren für Radfahrer verborgen sind\nund auch kein Verkehrszeichen darauf hinweist, dann ist ein Hinweis "Gefährliche Kurven", "Starkes Gefälle" oder "Straßenschäden" schon sinnvoll,\nman sollte aber bei dem Jargon der StVO bleiben.\n\\\n\\\nNatürlich habe ich auch nichts gegen aufmunternde motivierende Sprüche einzuwenden, welche ich farblich aber anders gestalten würde.\n\\\n\\\nKlar ist das eine kleine Kritik, die eher einen Denkanstoss geben soll und wobei bestimmt nicht jeder hier meiner Meinung ist.\n\\\n\\\nIch wollte es trotzdem loswerden, da wir uns gestern schon auf der Strecke darüber unterhalten haben.\n').build(),(new R).category(w.a.RTF).date(2016,5,30).name("Lutz Schröder").source(f.a.Facebook).text("\nUnd im nächsten Jahr gibt's bei der Warmverpflegung für die Vegetarier wenigstens ein Ketchup als Alternative zum Gulasch ??\n\\\n\\\nAnsonsten vielen Dank für die tolle Organisation und die schöne Strecke.\n").title("Wo bleiben die Vegetarier?").build(),(new R).category(w.a.RTF).date(2016,5,30).name("Andreas Klemt").source(f.a.Facebook).text("Sehr gut: Der Reiskuchen!").build(),(new R).category(w.a.RTF).date(2016,5,30,14,46).name("Martin Holtzmann").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...\n\\\n\\\nich bin die 158km Runde gefahren!  Sehr schöne, verkehrsarme Straßen (vor allem von Rosbach zur Vierbuchenmühle) nettes Verpflegungsteam!\n\\\nSchade, daß das vorhersagte Wetter eine niedrigeTeilnehmerzahl beschert hat, sogar auf Internet ist kein Verlaß!!\n\\\nLG Martin\n").build(),(new R).category(w.a.RTF).date(2016,5,30,13,4).location("Ruhrstadt Bochum").name("Martin Poettgen").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ...\n\\\n\\\nIhr habt eine tolle Marathon Strecke mit schönen Varianten erarbeitet.\n\\\nAn 2 – 3 Stellen hätte ein zusätzliches Schild ganz gut getan,\ndenn bei flotter Fahrt fehlte manchmal eine eindeutige Orientierung\nund Verfahrer und Umdreher kosten Zeit und Kraft (war wohl nicht der einzige).\n\\\nDie Wettervorhersage, die in Eurem Falle dann einmal nicht gestimmt hat (sonst hat sie uns dieses Jahr bei LBL und Röhn das vorausgesagte Mistwetter auch beschert)\nhat Euch leider die Teilnehmerzahlen verhagelt.\n\\\nJedenfalls bin ich noch nie einen Marathon gefahren, bei dem ich die ersten Mit-Teilnehmer bei Km 180 getroffen habe.\n\\\nInsofern einen ganz neue Erfahrung.\n\\\nNicht verzagen, ein Sportlerherz übersteht dies und nächstes Jahr wird die Wettervorhersage dann sicherlich auch stimmen, wie auch immer sie dann sein wird.\n\\\n\\\nMit sportlichen Grüßen\n\\\n\\\nMartin Poettgen,\n\\\n\\\nRuhrstadt Bochum\n").build(),(new R).category(w.a.RTF).date(2016,5,29,23,0).name("Andreas Tilles").organization("FB-Gruppe RTF und CTF - Radtourenfahrten des BDR (Bund Deutscher Radfahrer e.V.)").source(f.a.Facebook).text("\nBeste Warm-Verpflegung seit langem.\n\\\n\\\nOhne Nachschlag gingen Hermann und ich da nicht wieder auf die Strecke.\n").build(),(new R).category(w.a.RTF).date(2016,5,29,21,21).name("Volker Pütz").source(f.a.Facebook).text("\nEs war alles top top!\n\\\nBin den Marathon gefahren und es hat einfach Spaß gemacht.\n\\\n\\\nDanke an alle Helfer und das Orga Team!\n").build(),(new R).category(w.a.RTF).date(2016,5,29,20,50).name("Alexandra Raj").organization("FB-Gruppe RTF und CTF - Radtourenfahrten des BDR (Bund Deutscher Radfahrer e.V.)").source(f.a.Facebook).text("Herrliche Strecke ").build(),(new R).category(w.a.RTF).date(2016,5,29,20,33).name("Roland Liffers").source(f.a.Facebook).text("\n... schließe mich dem Lob von David Pandya vollumfänglich an, man kann es tendenziell nicht besser machen ...\n\\\nNächstes Jahr wird wieder die 1000er Marke geknackt 😀\n").title("Tolle Stullen, die 2.").build(),(new R).category(w.a.RTF).date(2016,5,29,20,20).name("Ludger Thier").organization("FB-Gruppe RTF und CTF - Radtourenfahrten des BDR (Bund Deutscher Radfahrer e.V.)").source(f.a.Facebook).text('\nWer sich heute trotz der besch... Wettervorhersage der "bergischen Herausforderung des RTC Köln" mit 2700hm auf knappen 200km gestellt hat,\nwurde bei herrlichem Wetter mit einer traumhaften Tour durch die wunderschöne Landschaft des Bergischen Landes belohnt.\n\\\n\\\nDie Sportler wurden von sehr freundlichen Helfern an den Kontrollstellen empfangen.\n\\\nDie Verpflegung war mehr als reichlich und sehr gut, insbesondere die Warmverpflegung, Gulasch mit Nudeln, war ein Genuß.\n\\\n\\\nEin großes Lob und DANKE an alle Helfer des RTC Köln für diesen tollen Tag.\n\\\n\\\nBis nächstes Jahr!\n').build(),(new R).category(w.a.RTF).date(2016,5,29,19,46).name("Angela Maja").source(f.a.Facebook).text("\nIch bedanke mich bei allen Beteiligten, die diese wunderbare Veranstaltung wieder möglich gemacht haben:\n\\\nKlasse Ausschilderung, super Verpflegung, schöne, verkehrsberuhigte Streckenführungen, herrliche Landschaften, nette Orga und Helfer - was will man mehr !\n\\\n\\\nIch freute mich, dass ich heute weder auf der 160 km Strecke noch auf dem anschl. Weg nach Hause von Gewitter oder Regen überrascht wurde - sondern eher von der Sonne.\n").title("Fabelhaft ...").build(),(new R).category(w.a.RTF).date(2016,5,29,19,11).name("David Pandya").organization("The Racing Club Rush (Gemeinschaft via Facebook)").source(f.a.Facebook).text("\nVielen vielen vielen lieben Dank RTC Köln e. V. 1972.\n\\\nDas war wirklich spitzenmässig organisiert und das kann auch mal gesagt werden.\n\\\nTolle Stullen, selbstgebackene Kuchen, leckeres Kölsch, überall super freundliche, gut gelaunte Menschen und die schönste ausgearbeitete Route der letzten 12 Monate!\n\\\n\\\nChapeau!\n").title("Tolle Stullen ...").build(),(new R).category(w.a.RTF).date(2016,5,29).location("Hürth Berrenrath").name("Stefan Schneider").organization("RV Morgenstern").source(f.a.Facebook).text("Wie gut ,dass ich den Apps heute nicht getraut habe und bei euch war 😀").build(),(new R).category(w.a.RTF).date(2016,5,29).name("Petra Ba").source(f.a.Facebook).text("Ein super Tag, und super Wetter ...").build(),(new R).category(w.a.RTF).date(2016,5,29,17,38).name("Bernd Doelp").source(f.a.Facebook).text("Das war eine schöne und anspruchsvolle Veranstaltung, vielen Dank.").build(),(new R).category(w.a.RTF).date(2016,5,29).name("Steffi Brockenhexe").source(f.a.Facebook).text("\nEs wurde alles gesagt.\n\\\n\\\nEinfach nur Top und alle die nur nach dem Wetterbericht gehen sind selber schuld.\n\\\nSuper Wetter mit reichlich Sonne auf knapp 200km ...\n").build(),(new R).category(w.a.RTF).date(2016,5,29,16,12).name("Horst Voll").source(f.a.Facebook).text("\nWar echt stark ...\n\\\n\\\nDie 200er war geil und, Nudeln mit Gulasch waren echt lecker ...\n").build(),(new R).category(w.a.RTF).date(2016,5,29,16,6).name("Horst Paesch").organization("RSC Erftstadt").source(f.a.Facebook).text("\nSitzen noch im Ziel und besaufen uns mit Alkoholfreiem Weizen ...\n\\\n\\\n...super Veranstaltung\n\\\n\\\n...super Wetter!\n").build(),(new R).category(w.a.RTF).date(2016,5,29).name("Mario Schmitt").source(f.a.Facebook).text("\nSuper Organisation.\n\\\nDie Strecke war klar und deutlich ausgeschildert und die Verpflegung war reichlich.\n\\\n\\\nTop! 👍\n").build(),(new R).category(w.a.RTF).date(2016,5,29).name("Volker Schmitz").source(f.a.Facebook).text("\nTolles Event, klasse Orga!\n\\\n\\\nMich hat am meisten beeindruckt wie gut die Strecke ausgeschildert war!\n\\\n\\\nTop! 👍\n").build(),(new R).category(w.a.RTF).date(2016,5,29).name("Se Sandra").source(f.a.Facebook).text("\nWar 'ne schöne Strecke und Verpflegung war reichlich da an den Kontrollstellen! 👍 👍\n\\\n\\\nWettervorhersage?\n\\\nWas ist das? 😉\n").title("Tadel gibt es keinen!").build(),(new R).category(w.a.RTF).date(2016,5,29,14,36).name("Ros Si").source(f.a.Facebook).text("\nWar eine super 158er RTF.\n\\\nAlles klasse, sogar das Wetter.\n\\\n\\\nVielen Dank an den RTC.\n").build(),(new R).category(w.a.RTF).date(2016,5,29,14,0).name("Patrock Cyclista").source(f.a.Facebook).text("Danke für heute. Super Orga, schöne Strecke, gerne wieder.").build(),(new R).category(w.a.RTF).date(2016,5,29,13,52).name("Jochen Güttes").source(f.a.Facebook).text("\nDas mit das mit dem Wettergott hat hervorragend funktioniert.\n\\\nLeider verlassen sich mehr Leute auf ihre Wetterapp am Tag zuvor als morgens einmal aus dem Fenster zu schauen.\n\\\nIch bin trocken geblieben und es war eine tolle Veranstaltung.\n\\\nVielen Dank\n").title("Ihr habt mehr Teilnehmer verdient gehabt. Vor allem beim Marathon ...").build()],C=[(new R).answer("Dem Dieter kann geholfen werden, Brille ist da, Kontakt wird aufgenommen ...").category(w.a.CTF).date(2017,11,11,17,1).name("Dieter Roggensack").source(f.a["E-Mail"]).text("\nHallo RTC, ich/wir wollte/n nur sagen, dass Eure CTF einmal wieder sehr schön und ausgezeichnet organisiert war.\n\\\nWenn ich auch nicht unbedingt begeistert von den 2 Downhill-Strecken war (ich bin dafür zu alt und zu ängstlich), so war der übrige Teil der 55-er Runde wunderbar.\n\\\nVielen Dank  für all Eure Mühen.\n\\\nSeit der CTF bei Euch vermisse ich meine Radbrille.\n\\\nIch kann mir nur noch vorstellen, sie beim Ziel innen oder draußen liegen gelassen zu haben.\n\\\nEs handelt sich um die Marke Eagle Five mit eingebautem Leseteil.\n\\\nSollte sie gefunden sein, bitte ich um Kontakt per email.\n\\\nViele Grüße, Dieter Roggensack...").title("Feedback wegen ...CTF Wahnbachtour").build(),(new R).category(w.a.CTF).date(2017,10,30,9,48).name("Herwig Barthes").source(f.a.Facebook).text("\nDie CTF an der Wahnbachtalsperre war großartig und hat großen Spaß gemacht.\n\\\nEin Riesenkompliment an alle Helfer und Organisatoren. Super Service auf der Strecke und am Klubhaus.\n\\\nBesonders gut gefallen hat mir der Grill, die Waschstation und die Erbsensuppe.\n\\\n\\\nEinen kleinen Verbesserungsvorschlag hätte ich:\n\\\nVielleicht könnte man in den GPSies-Track beim nächsten Mal Abbiegehinweise einbauen.\n\\\nIch weiß, das ist eine ziemliche Fummelei, würde aber die Navigation erleichtern.\n\\\n\\\nAnsonsten alles top!!\n\\\n\\\nVielen Dank!\n\\\nGruß H. Barthes\n").build(),(new R).category(w.a.CTF).date(2017,10,29,18,0).name("Wilfried Goesgens").source(f.a.Facebook).text("\nHallo liebes RTC Team,\n\\\nSuper Tour, hat viel Spaß gemacht.\n\\\nWie gestern schon persönlich erzählt, war ein Abzweig auf Lohmar zu in der Abfahrt schwer zu sehen - einige haben sich verfahren ...\n\\\nDa wir gestern den Punkt nicht genau festmachen konnten, hier mein Strava Track, bei KM 73,3 ist es passiert ...\n\\\nEvtl. müsste man hier den Abbieger mit Flatterband auf dem Boden markieren, von oben kommend sah man die Markierung quasi nicht.\n").build(),(new R).category(w.a.CTF).date(2017,10,29,18,0).name("Jan Koza").source(f.a.Facebook).text("\nEine tolle Strecke ...\n\\\nHerzlichen Dank!\n").build(),(new R).category(w.a.CTF).date(2017,10,29,18,0).name("Birgit Frings-Salz").source(f.a.Facebook).text("Uns, als Gruppe Säuwätz, hat es auch super gut gefallen. Grosses Lob ...").build(),(new R).category(w.a.CTF).date(2017,10,28,21,30).name("Christoph Werner").source(f.a.Facebook).text("War eine schöne Veranstaltung. Gerne nächstes Jahr wieder.").build(),(new R).category(w.a.CTF).date(2017,10,28,21,30).name("Mika Kali").source(f.a.Facebook).text("Wie immer: Klasse CTF ...").build(),(new R).category(w.a.CTF).date(2017,10,28,21,30).name("Thomas Zengerle").source(f.a.Facebook).text("\nHallo,\n\\\ndas war heute eine tolle Runde. Ihr habt eine klasse Orga gehabt.\n\\\nHoffentlich geht es dem Verletzten bald wieder gut.\n\\\nSchönen Gruß Thomas\n").build(),(new R).category(w.a.CTF).date(2017,10,28,21,30).name("Andreas Diehl").source(f.a.Facebook).text("Schön war's ...").build(),(new R).category(w.a.CTF).date(2017,10,28,21,30).name("Jürgen Em").source(f.a.Facebook).text("\nTolle Veranstaltung; tolle Verpflegung; tolle Strecke;\n\\\nAusschilderung hätte etwas besser sein können, aber irgendwas ist immer.\n\\\nBin nächstes Jahr gerne wieder dabei!\n").build(),(new R).category(w.a.CTF).date(2017,10,28,21,30).name("Bernd Doelp").source(f.a.Facebook).text("\n... dieses Jahr hat wirklich alles perfekt gepasst.\n\\\nSuper ausgeschildert, Verpflegung mehr als genug ...\n\\\nVIELEN DANK\n                ").build(),(new R).category(w.a.CTF).date(2017,10,28,21,30).name("Konstantin Sakellaris").source(f.a.Facebook).text("\nHallo RTC-Köln, ich fahr seit grob 2 Jahren erst MTB, eure CTF war meine erste die ich gefahren bin.\n\\\nIch möchte mich ganz herzlich bei euch für diese Tour bedanken, vor allem an das Team K1/K3.\n\\\nDa hatte ich bei der erste Anfahrt einen Cheesburger bestellt. Als ich zur dritten Kontrolle wieder da war, habe ich doch einen bekommen, echt kreativ dieses Team.\n\\\n2 TUC Kekse und dazwischen eine Scheibe Käse. Lecker. Bis zum nächstem Jahr.\n\\\n                ").build(),(new R).category(w.a.CTF).date(2017,10,28,21,30).name("Mischa Breuer").source(f.a.Facebook).text("War echt super. Hoffentlich 2018 wieder ...").build(),(new R).category(w.a.RTF).date(2017,5,29,20,30).name("Jochen Güttes").organization("Präsident des RTC Mehlem").source(f.a.Facebook).text("\nDanke für die TOP Organisation, die gute Beschilderung und die abwechslungsreiche Verpflegung an den Kontrollen und im Ziel.\n\\\nEs war wieder super bei euch.\n                ").build(),(new R).category(w.a.RTF).date(2017,5,29,20,30).name("Roland Liffers").source(f.a.Facebook).text("\nSchliesse mich meinem Sportskamerad Jochen Güttes vollumfänglich an.\n\\\nDer RTC Köln hat trotz immer schwerer werdenden Rahmenbedingungen eine Super-Veranstaltung auf die Beine gestellt.\n\\\nDanke dafür!\n").build(),(new R).category(w.a.RTF).date(2017,5,29,20,30).name("Horst Voll").source(f.a.Facebook).text("Vielen Dank für die heutige Betreuung.... war TippiToppi.").build(),(new R).category(w.a.RTF).date(2017,5,29,20,30).name("Uli Fritzsche").source(f.a.Facebook).text("Und wir danken für die tolle Orga!").build(),(new R).category(w.a.RTF).date(2017,5,28,20,30).name("Frank Müller").source(f.a.Facebook).text("\nAusschilderung gut, Strecke perfekt, Verpflegung ausgezeichnet (das Gulasch mit Nudeln sehr lecker).\n\\\nVielen Dank\n").build(),(new R).category(w.a.RTF).date(2017,5,28,20,30).name("Mika Kali").source(f.a.Facebook).text("\nHallo, danke nochmal für die tolle RTF gestern!\n\\\nIch habe nur einen kleinen Kritikpunkt:\n\\\nDie Ortsdurchsfahrt Much war auch in diesem Jahr wieder Horror. Da wird durch Autofahrer genötigt, was das Zeug hält ...\n").build(),(new R).category(w.a.RTF).date(2017,5,28,20,57).name("Dirk Oliver Heppert").organization("RSV Staubwolke Refrath").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nich/wir wollte/n nur sagen, dass ... Eure RTF war wieder bestens organisiert. Schöne anspruchsvolle Strecken, gute Verpflegung und präzise Ausschilderung.\n\\\nHat wieder alles gepasst.\n\\\n\\\nVG\n\\\nDirk Oliver Heppert RSV Staubwolke Refrath\n").build()],E=[(new R).category(w.a.CTF).date(2018,10,28,0,0).name("Andreas Reineke").source(f.a.Facebook).text("\nSchöne Strecke - aber die Markierungsdiebe waren zu aktiv.\n\\\n\\\nDen Vereinsmitgliedern tat es total leid, aber die konnten nicht so schnell nachschildern bzw. Flaggen, wie die Markierungen geklaut worden sind.\n\\\nEs waren alle super nett!!\n\\\nEs war eine sehr schöne Veranstaltung.\n").build(),(new R).category(w.a.CTF).date(2018,10,28,0,0).name("Vamos Bala").source(f.a.Facebook).text("\nOrga an Start/Ziel super und sehr nette motivierte Helfertruppe ...\n\\\nSchön, dass Ihr die Veranstaltung gewuppt bekommt und sie auch weiter macht ...\n").build(),(new R).category(w.a.CTF).date(2018,10,27,16,36).name("Bernd Doelp").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\ngenau wie letztes Jahr war alles wieder perfekt.\n\\\n\\\nVielen Dank und bis nächstes Jahr, diese Veranstaltung ist auf jeden Fall gesetzt.\n\\\n\\\nIch freue mich jetzt schon ...\n\\\nViele Grüße\n\\\n\\\nBernd\n").build(),(new R).category(w.a.RTF).date(2018,5,28,17,0).name("Profitrise Sports").source(f.a.Facebook).text("Und danke an den RTC Köln e. V. 1972 für die tolle RTF heute!").build(),(new R).category(w.a.RTF).date(2018,5,28,17,0).name("Petra Humbach").source(f.a.Facebook).text("Schade, da bietet ihr an, ab Pohlhausen zu starten und dann gibt es ab 9:15 Uhr keine Startkarten mehr.").build(),(new R).category(w.a.RTF).date(2018,5,28,17,0).name("Jochen Güttes").source(f.a.Facebook).text("\nWir Teilnehmer sind begeistert.\n\\\nStreckenführung, Verpflegung, Personal ... alles TOP.\n\\\nDanke für die Gastfreundschaft.\n                ").build(),(new R).category(w.a.RTF).date(2018,5,28,17,0).name("Ros Si").source(f.a.Facebook).text("\nDie Fahrt hat Tradition.\n\\\nUnd Tradition hat auch die perfekte Organisation.\n\\\nSuper Ausschilderung, super Getränke und natürlich die obligatorischen RTF Nutellabrote.\n\\\nUnd vieles mehr an den Kontrollen.\n\\\nRiesen Dankeschön.\n\\\nHat riesig Spaß gemacht bei euch zu fahren.\n\\\nNächstes Jahr wieder.\n").build(),(new R).category(w.a.RTF).date(2018,5,28,17,0).name("Angela Maja").source(f.a.Facebook).text("\nEs war wunderbar 😊\n\\\nVielen Dank für tolle Streckenführung, Verpflegung, freundliche Orga und Helfer!\n\\\nAlles bestens.\n\\\n\\\n161 km RTF Strecke und dann nach Hause waren dann für mich bei meiner ersten RTF in diesem Jahr ein Marathon ... 😊").build(),(new R).category(w.a.RTF).date(2018,5,27,17,1).name("Harald Seidenberg").source(f.a["E-Mail"]).text("\nHallo RTC,\n\\\n\\\nIch/wir wollte/n nur sagen, dass ...  ich heute nach 25 Jahren wieder mal eine RTF gefahren bin.\n\\\nMir hat die RTF heute Kurzstrecke sehr gut gefallen hat. Wetter schön, Temperatur wunderbar.\n\\\ngut ausgeschildert.\n\\\nWas ich gegenüber damals vermisst habe waren Verkaufstand  mit Trikots oder…. .\n\\\nVielleicht hat sich in der Zeit da was verändert.\n\\\nSollte keine Kritik sein.\n\\\nNur eine Anmerkung.\n\\\nHarry\n").title("Feedback wegen ... RTF 27.05.2018").build(),(new R).category(w.a.RTF).date(2018,5,27,13,54).name("Dirk Oliver Heppert").organization("RSV Staubwolke Refrath").source(f.a["E-Mail"]).text("\nHallo RTC, ich/wir wollte/n nur sagen, dass ... ich wieder total begeistert bin von Eurer RTF.\n\\\nWie immer Toporganisation, präzise Ausschilderung und interessante Streckenführung.\n\\\nBin heute nur die 51er Schleife mit meinem Kollegen gefahren, da ich noch von gestern die Höhenmeter der RTF in Wuppertal in den Beinen habe.\n\\\nAber auch die kurze Schleife hat ihre Reize.\n\\\nKenne jetzt auf jeden Fall alle Strecken.\n\\\nEure RTF gehört zu den Besten im Bezirk Köln-Bonn.\n\\\n\\\nLG Dirk Heppert- RSV Staubwolke Refrath- Bezirksmeister 2017 Köln-Bonn\n").title("Feedback wegen ...RTF 2018").build()],x=[(new R).category(w.a.CTF).date(2019,10,28,20,0).name("Franz Böhm").source(f.a.Facebook).text("Ihr macht das richtig gut! Freue mich auf nächstes Jahr.").build(),(new R).category(w.a.CTF).date(2019,10,28,20,0).name("Martin Rupp").source(f.a.Facebook).text("\nSehr schöne Strecken ...\n\\\nsuper Verpflegung ...\n\\\nschöne Lounge im Ziel ...\n\\\nmit Grill und Bierchen ...\n\\\nweiter so.\n").build(),(new R).category(w.a.CTF).date(2019,10,28,20,0).name("Andreas Schäfer").source(f.a.Facebook).text("\nSehr schöne Tour bei tollem Sonnenschein\n\\\nDanke an alle fleißigen Helferlein an den verschiedenen Kontrollpunkten.\n\\\nDie 55er Strecke war bis auf 2 oder 3 Stellen sehr gut markiert.\n").build(),(new R).category(w.a.CTF).date(2019,10,28,20,0).name("Dirk Weinbörner").source(f.a.Facebook).text("Tolle Tour, klasse Verpflegung - richtig gut gemacht - nächstes Jahr auf jeden Fall wieder.").build(),(new R).category(w.a.CTF).date(2019,10,28,20,0).name("Matthes Heise").source(f.a.Facebook).text("\nWar eine sehr schöne Tour. Die Kontroll- und Verpflegungspunkte waren super.\n\\\nEinfach gesagt, ich freu mich schon auf's nächste Jahr!\n").build(),(new R).category(w.a.CTF).date(2019,10,28,20,0).name("Stephanie Hilton").source(f.a.Facebook).text("Tolle Tour! Hat Spass gemacht!!!").build(),(new R).category(w.a.CTF).date(2019,10,28,20,0).name("Jochen Güttes").source(f.a.Facebook).text("Eine top organisierte Veranstaltung. Hat riesen Spaß gemacht.").build()],D=Object(k.c)("guestbook",{state:function(){return{db2019:x,db2018:E,db2017:C,db2016:V,db2015:M,db2014:z,db2012:v}},getters:{all:function(e){return[].concat(e.db2019,e.db2018,e.db2017,e.db2016,e.db2015,e.db2014,e.db2012)}}}),y=Object(c.c)({__name:"guestbook",setup:function(e){return{__sfc:!0,icons:{mdiEmailSend:o.k},items:D().all,mdiEmailSend:o.k,CGuestbook:m.default}}}),K=r(69),component=Object(K.a)(y,(function(){var e=this,n=e._self._c,r=e._self._setupProxy;return n(l.a,{attrs:{id:"GuestbookView",flat:""}},[n(l.e,{staticClass:"text-body-1 text-sm-body-2 text-md-h6 text-lg-h5 text-xl-h4"},[e._v("Gästebuch")]),e._v(" "),n(l.c,{staticClass:"text-body-2 text-sm-subtitle-2 text-md-subtitle-1 text-lg-h6 text-xl-h5"},[e._v("\n        Briefpost bitte immer an: RTC Köln, Postfach 990103, 51083 Köln\n    ")]),e._v(" "),n(l.b,[n(t.a,{staticClass:"text-body-2 text-sm-body-2 text-lg-body-1",staticStyle:{"background-color":"var(--v-primary-base)",color:"var(--v-accent-base)"},attrs:{href:"mailto:PR@rtc-koeln.de?subject=G%C3%A4stebuch%20-%20Thema\n            &body=Hallo%20RTC%20K%C3%B6ln%2C%0D%0A%0D%0APlatzhalter%20f%C3%BCr%20den%20G%C3%A4stebucheintrag%0D%0A%0D%0A\n            --%0D%0AViele%20Gr%C3%BC%C3%9Fe%0D%0AMax%20Mustermann%0D%0AAus%20K%C3%B6ln"}},[e._v("\n            Gästebucheintrag hinzufügen\n            "),n(d.a,{attrs:{right:""},domProps:{textContent:e._s(r.icons.mdiEmailSend)}})],1)],1),e._v(" "),n(l.d,[n(h.b,{staticClass:"d-flex justify-center",attrs:{dense:""}},e._l(r.items,(function(e,t){return n(h.a,{key:t,attrs:{cols:"auto"}},[n(r.CGuestbook,{attrs:{value:e}})],1)})),1)],1)],1)}),[],!1,null,"48a04430",null);n.default=component.exports}}]);